What does the Error "Map on Result" mean in Rust. Here is some context:




let length = {

                let res = parse_track_entry(buffer.data());

                match res {

                    Ok((remainder, parsed)) => {

                        anchor_message.track_entries.push(parsed);

                        buffer.data().offset(remainder)

                    }

                    Err(Err::Error(e)) | Err(Err::Failure(e)) => {

                        return Err(CustomErrors::NoIDNStructParsed(

                            "AnchorMessageEntry".to_string(),

                            e.code.description().to_string(),

                        )); # THIS ERROR IS RETURNING Map on Result

                    }

                    Err(Err::Incomplete(_i)) => continue,

                }

            };




